input.command:
ssh -i /home/agent/.ssh/id_ed25519 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -p 22 audit@target-svc-compliant-471b0f.grundschutz-lab.svc.cluster.local "
echo '=== /usr/local/share/ca-certificates/ (lokale CAs) ===';
ls -la /usr/local/share/ca-certificates/ 2>&1;
echo '=== /etc/ca-certificates.conf (aktivierte CAs) ===';
grep -v '^#' /etc/ca-certificates.conf 2>/dev/null | grep -v '^$' | head -30;
echo '... (Zeilen gesamt):';
grep -c . /etc/ca-certificates.conf 2>/dev/null;
echo '=== dpkg: Paket ca-certificates ===';
dpkg -l ca-certificates 2>/dev/null;
"

ssh -i /home/agent/.ssh/id_ed25519 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -p 22 audit@target-svc-compliant-471b0f.grundschutz-lab.svc.cluster.local "
echo '=== Alle Eintraege in /etc/ca-certificates.conf ===';
grep -v '^#' /etc/ca-certificates.conf | grep -v '^$';
"

ssh -i /home/agent/.ssh/id_ed25519 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -p 22 audit@target-svc-compliant-471b0f.grundschutz-lab.svc.cluster.local "
echo '=== /etc/ssl/certs/ - Nicht-mozilla-Symlinks (potenzielle lokale CAs) ===';
ls -la /etc/ssl/certs/ | grep -v '^total' | grep -v ' -> /usr/share/ca-certificates/mozilla/' | grep -v '^d' | head -40;
echo '=== /etc/ssl/certs/ Gesamtanzahl ===';
ls /etc/ssl/certs/ | wc -l;
echo '=== /etc/ssl/certs/ - Symlinks die NICHT auf mozilla zeigen ===';
find /etc/ssl/certs/ -type l | while read f; do target=\$(readlink \"\$f\"); echo \"\$f -> \$target\"; done | grep -v 'mozilla/' | grep -v 'ca-certificates.crt';
"

ssh -i /home/agent/.ssh/id_ed25519 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -p 22 audit@target-svc-compliant-471b0f.grundschutz-lab.svc.cluster.local "
echo '=== .pem-Symlinks die NICHT auf /usr/share/ca-certificates/mozilla zeigen ===';
find /etc/ssl/certs/ -name '*.pem' -type l | while read f; do
  target=\$(readlink \"\$f\");
  echo \"\$f -> \$target\";
done | grep -v '/usr/share/ca-certificates/mozilla/';
echo '=== Echte Dateien (nicht Symlinks) in /etc/ssl/certs/ ===';
find /etc/ssl/certs/ -maxdepth 1 ! -type l -type f 2>/dev/null;
echo '=== Verzeichnisse ausser dem Verzeichnis selbst ===';
find /etc/ssl/certs/ -maxdepth 1 -type d ! -path '/etc/ssl/certs/' 2>/dev/null;
"

ssh -i /home/agent/.ssh/id_ed25519 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -p 22 audit@target-svc-compliant-471b0f.grundschutz-lab.svc.cluster.local "
echo '=== dpkg-Integritaetspruefung ca-certificates ===';
sudo /usr/bin/dpkg -V ca-certificates 2>&1;
echo '=== Paketinhalt ca-certificates (installierte Dateien) ===';
dpkg -L ca-certificates 2>/dev/null | head -20;
echo '=== /usr/share/ca-certificates/ - nur Eintraege ausserhalb von mozilla/ ===';
find /usr/share/ca-certificates/ -type f | grep -v '/mozilla/' | head -20;
echo '=== Anzahl .crt in /usr/share/ca-certificates/mozilla/ ===';
ls /usr/share/ca-certificates/mozilla/ | wc -l;
echo '=== Java Keystores (falls vorhanden) ===';
find /etc /usr/lib/jvm /opt -name 'cacerts' -o -name '*.jks' -o -name '*.p12' 2>/dev/null | head -10;
echo '=== NSS / certutil-Datenbanken ===';
find /etc /home /root -name 'cert8.db' -o -name 'cert9.db' 2>/dev/null | head -10;
"

ssh -i /home/agent/.ssh/id_ed25519 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -p 22 audit@target-svc-compliant-471b0f.grundschutz-lab.svc.cluster.local "
echo '=== Abgleich: .pem-Dateien in /etc/ssl/certs vs mozilla/*.crt in /usr/share/ca-certificates ===';
echo 'Anzahl .pem-Symlinks in /etc/ssl/certs:';
find /etc/ssl/certs/ -name '*.pem' -type l | wc -l;
echo 'Anzahl Hash-Symlinks (.0 .1 etc) in /etc/ssl/certs:';
find /etc/ssl/certs/ -name '*.0' -o -name '*.1' | wc -l;
echo '=== /etc/ca-certificates/update.d/ (Hooks) ===';
ls -la /etc/ca-certificates/update.d/ 2>/dev/null;
echo '=== Anzahl CA-Eintraege in ca-certificates.conf ===';
grep -v '^#' /etc/ca-certificates.conf | grep -v '^$' | wc -l;
echo '=== Anzahl .crt in /usr/share/ca-certificates/mozilla/ ===';
ls /usr/share/ca-certificates/mozilla/ | wc -l;
echo '=== Ist Differenz vorhanden? .pem-Dateien NICHT in mozilla/*.crt ===';
# Checke ob pem-Dateinamen (ohne .pem) einem mozilla-Eintrag ohne .crt entsprechen
pem_names=\$(find /etc/ssl/certs/ -name '*.pem' -type l -exec basename {} .pem \;| sort)
mozilla_names=\$(ls /usr/share/ca-certificates/mozilla/ | sed 's/\\.crt\$//' | sort)
comm -23 <(echo \"\$pem_names\") <(echo \"\$mozilla_names\") 2>/dev/null || echo 'Vergleich nicht moeglich';
"

ssh -i /home/agent/.ssh/id_ed25519 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -p 22 audit@target-svc-compliant-471b0f.grundschutz-lab.svc.cluster.local "
echo '=== Suche nach weiteren .crt/.pem/.der Dateien ausserhalb bekannter Pfade ===';
find / -maxdepth 6 \( -name '*.crt' -o -name '*.pem' -o -name '*.cer' \) \
  ! -path '/etc/ssl/*' \
  ! -path '/usr/share/ca-certificates/*' \
  ! -path '/proc/*' \
  ! -path '/sys/*' \
  ! -path '/dev/*' \
  ! -path '/run/*' \
  2>/dev/null | grep -v 'doc' | head -30;
echo '=== /usr/share/ca-certificates ausserhalb mozilla/ ===';
ls /usr/share/ca-certificates/ 2>/dev/null;
echo '=== Python certifi (falls installiert) ===';
find /usr /opt -path '*/certifi/cacert.pem' 2>/dev/null | head -5;
echo '=== curl CA-Bundle-Konfiguration ===';
curl-config --ca 2>/dev/null || echo 'curl-config nicht verfuegbar';
"

ssh -i /home/agent/.ssh/id_ed25519 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -p 22 audit@target-svc-compliant-471b0f.grundschutz-lab.svc.cluster.local "
echo '=== /usr/lib/ssl/cert.pem - Ziel pruefen ===';
ls -la /usr/lib/ssl/cert.pem 2>/dev/null;
readlink -f /usr/lib/ssl/cert.pem 2>/dev/null;
echo '=== /usr/lib/ssl/ Verzeichnisinhalt ===';
ls -la /usr/lib/ssl/ 2>/dev/null;
"
